const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
const raw = binaryData.toString('utf8');
const trades = JSON.parse(raw);

if (trades.length === 0) {
  return [{ json: { error: 'No settled trades in export', trades: [] } }];}
const cityConfig = {
  nyc:          { lat: 40.77, lon: -73.87, station: 'KLGA', unit: 'fahrenheit', tz: 'America/New_York',       iem_station: 'LGA', iem_network: 'NY_ASOS' },
  chicago:      { lat: 41.98, lon: -87.90, station: 'KORD', unit: 'fahrenheit', tz: 'America/Chicago',        iem_station: 'ORD', iem_network: 'IL_ASOS' },
  miami:        { lat: 25.79, lon: -80.29, station: 'KMIA', unit: 'fahrenheit', tz: 'America/New_York',       iem_station: 'MIA', iem_network: 'FL_ASOS' },
  atlanta:      { lat: 33.64, lon: -84.43, station: 'KATL', unit: 'fahrenheit', tz: 'America/New_York',       iem_station: 'ATL', iem_network: 'GA_ASOS' },
  dallas:       { lat: 32.90, lon: -97.04, station: 'KDFW', unit: 'fahrenheit', tz: 'America/Chicago',        iem_station: 'DFW', iem_network: 'TX_ASOS' },
  seattle:      { lat: 47.45, lon: -122.31,station: 'KSEA', unit: 'fahrenheit', tz: 'America/Los_Angeles',    iem_station: 'SEA', iem_network: 'WA_ASOS' },
  denver:       { lat: 39.86, lon: -104.67,station: 'KDEN', unit: 'fahrenheit', tz: 'America/Denver',         iem_station: 'DEN', iem_network: 'CO_ASOS' },
  los_angeles:  { lat: 33.94, lon: -118.41,station: 'KLAX', unit: 'fahrenheit', tz: 'America/Los_Angeles',    iem_station: 'LAX', iem_network: 'CA_ASOS' },
  toronto:      { lat: 43.68, lon: -79.63, station: 'CYYZ', unit: 'celsius',    tz: 'America/Toronto',        iem_station: 'CYYZ', iem_network: 'CA_ON_ASOS' },
  london:       { lat: 51.51, lon: 0.05,   station: 'EGLC', unit: 'celsius',    tz: 'Europe/London',          iem_station: 'EGLC', iem_network: 'GB__ASOS' },
  seoul:        { lat: 37.46, lon: 126.44, station: 'RKSI', unit: 'celsius',    tz: 'Asia/Seoul',             iem_station: 'RKSI', iem_network: 'KR__ASOS' },
  paris:        { lat: 48.73, lon: 2.37,   station: 'LFPO', unit: 'celsius',    tz: 'Europe/Paris',           iem_station: 'LFPO', iem_network: 'FR__ASOS' },
  tel_aviv:     { lat: 32.01, lon: 34.77,  station: 'LLBG', unit: 'celsius',    tz: 'Asia/Jerusalem',         iem_station: 'LLBG', iem_network: 'IS__ASOS' },
  sao_paulo:    { lat: -23.43,lon: -46.47, station: 'SBGR', unit: 'celsius',    tz: 'America/Sao_Paulo',      iem_station: 'SBGR', iem_network: 'BR__ASOS' },
  buenos_aires: { lat: -34.82,lon: -58.54, station: 'SAEZ', unit: 'celsius',    tz: 'America/Argentina/Buenos_Aires', iem_station: 'SAEZ', iem_network: 'AR__ASOS' },
};
const cityDates = {};
for (const t of trades) {
  const key = `${t.city}|${t.target_date}`;
  const cfg = cityConfig[t.city];
  if (!cfg) continue;

  if (!cityDates[key]) {
    cityDates[key] = {
      city: t.city,
      target_date: t.target_date,
      lat: cfg.lat,
      lon: cfg.lon,
      station: cfg.station,
      unit: cfg.unit,
      tz: cfg.tz,
      iem_station: cfg.iem_station,   // ← add
      iem_network: cfg.iem_network,   // ← add
      trade_count: 0,
      trades: []
    };
  }
  cityDates[key].trade_count++;
  cityDates[key].trades.push(t);
}
return Object.values(cityDates).map(cd => ({ json: cd }));

const trades = $('Read Settled Trades').all();
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const tradeItem = trades[i].json;
  const merged = items[i].json;

  const city = tradeItem.city;
  const date = tradeItem.target_date;
  const cityTrades = tradeItem.trades;

  // --- Extract Open-Meteo observation ---
  let om_temp = null;
  try {
    const omDaily = merged.daily;
    if (omDaily && omDaily.temperature_2m_max && omDaily.temperature_2m_max[0] != null) {
      om_temp = omDaily.temperature_2m_max[0];
    }
  } catch (e) {
    om_temp = null;
  }

  // --- Extract IEM observation ---
  let iem_temp = null;
  try {
    const iemData = merged.data;
    if (iemData && iemData.length > 0) {
      const obs = iemData[0];
      // IEM always returns both max_tmpf and max_tmpc
      // Match to bracket_unit of trades for this city
      const bracketUnit = cityTrades[0]?.bracket_unit;
      if (bracketUnit === 'F') {
        iem_temp = obs.max_tmpf != null ? obs.max_tmpf : null;
      } else {
        if (obs.max_tmpc != null) {
          iem_temp = obs.max_tmpc;
        } else if (obs.max_tmpf != null) {
          iem_temp = Math.round(((obs.max_tmpf - 32) * 5 / 9) * 10) / 10;
        }
      }
    }
  } catch (e) {
    iem_temp = null;
  }

  // --- Estimate WU temp from winning bracket midpoint ---
  let wu_temp = null;
  const winningTrade = cityTrades.find(t => t.outcome === 1 && t.side === 'YES');
  if (winningTrade) {
    wu_temp = (winningTrade.bracket_lower + winningTrade.bracket_upper) / 2;
  }

  // --- Compute divergences ---
  const om_divergence = (om_temp != null && wu_temp != null) ?
    Math.round((om_temp - wu_temp) * 10) / 10 : null;
  const iem_divergence = (iem_temp != null && wu_temp != null) ?
    Math.round((iem_temp - wu_temp) * 10) / 10 : null;
  const om_iem_divergence = (om_temp != null && iem_temp != null) ?
    Math.round((om_temp - iem_temp) * 10) / 10 : null;

  // --- Bracket flip analysis per trade ---
  const tradeDetails = cityTrades.map(t => {
    const low = t.bracket_lower;
    const high = t.bracket_upper;
    const wu_hit = wu_temp != null && wu_temp >= low && wu_temp < high;
    const om_hit = om_temp != null && om_temp >= low && om_temp < high;
    const iem_hit = iem_temp != null && iem_temp >= low && iem_temp < high;

    return {
      trade_id: t.trade_id,
      bracket_label: t.bracket_label,
      bracket_lower: low,
      bracket_upper: high,
      bracket_unit: t.bracket_unit,
      side: t.side,
      entry_price: t.entry_price,
      pnl: t.pnl,
      model_prob: t.model_prob,
      market_prob: t.market_prob,
      wu_hit,
      om_hit: om_temp != null ? om_hit : null,
      iem_hit: iem_temp != null ? iem_hit : null,
      om_flipped: (om_temp != null && wu_temp != null) ? (om_hit !== wu_hit) : null,
      iem_flipped: (iem_temp != null && wu_temp != null) ? (iem_hit !== wu_hit) : null,
    };
  });

  const bracketUnit = cityTrades[0]?.bracket_unit || '';

  results.push({
    json: {
      city,
      date,
      station: tradeItem.station,
      bracket_unit: bracketUnit,
      wu_temp,
      om_temp,
      iem_temp,
      om_divergence,
      iem_divergence,
      om_iem_divergence,
      n_trades: cityTrades.length,
      om_n_flipped: tradeDetails.filter(f => f.om_flipped === true).length,
      iem_n_flipped: tradeDetails.filter(f => f.iem_flipped === true).length,
      trade_details: tradeDetails,
      has_om: om_temp != null,
      has_iem: iem_temp != null,
      has_wu: wu_temp != null,
    }
  });
}

return results;

const items = $input.all();
const runDate = new Date().toISOString().split('T')[0];

let totalPnl = 0;
let wins = 0;
let losses = 0;
let totalTrades = 0;
let flips_om = 0;
let flips_iem = 0;
const cityResults = [];

for (const item of items) {
  const d = item.json;
  for (const t of d.trade_details) {
    totalTrades++;
    const pnl = t.pnl || 0;
    totalPnl += pnl;
    if (pnl > 0) wins++;
    else if (pnl < 0) losses++;
    if (t.om_flipped) flips_om++;
    if (t.iem_flipped) flips_iem++;
  }

  const pnlSum = d.trade_details.reduce((s, t) => s + (t.pnl || 0), 0);
  const emoji = pnlSum >= 0 ? '\u2705' : '\u274c';
  cityResults.push(
    `${emoji} ${d.city}: $${pnlSum.toFixed(2)} (${d.n_trades} trade${d.n_trades > 1 ? 's' : ''})`
    + (d.om_iem_divergence != null ? ` | OM-IEM: ${d.om_iem_divergence > 0 ? '+' : ''}${d.om_iem_divergence}\u00b0` : '')
  );
}

const winRate = totalTrades > 0 ? ((wins / totalTrades) * 100).toFixed(0) : 0;
const pnlEmoji = totalPnl >= 0 ? '\ud83d\udcc8' : '\ud83d\udcc9';

let msg = `${pnlEmoji} *Wethr Divergence Audit*\n`;
msg += `\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n`;
msg += `*Date:* ${runDate}\n`;
msg += `*Trades:* ${totalTrades} | *W/L:* ${wins}/${losses} (${winRate}%)\n`;
msg += `*Net PnL:* $${totalPnl.toFixed(2)}\n\n`;

if (flips_om > 0 || flips_iem > 0) {
  msg += `\u26a0\ufe0f *Bracket Flips:* OM=${flips_om}, IEM=${flips_iem}\n\n`;
}

msg += `*By City:*\n`;
msg += cityResults.join('\n');

return [{ json: { message: msg } }];

// Start Run: insert a row into audit_runs with run_id = n8n execution id.
// Downstream nodes reach back via $('Start Run').first().json._run_id.
const sqlite3 = require('sqlite3');
const runId      = String($execution.id);
const startedAt  = new Date().toISOString();
const triggerMode = ($execution && $execution.mode) ? $execution.mode : 'manual';
const workflowId = ($workflow && $workflow.id) ? $workflow.id : null;

const db = new sqlite3.Database('/data/wethr/wethr_audit.db');
await new Promise((resolve, reject) => {
  db.run(
    `INSERT INTO audit_runs (run_id, started_at, status, trigger_type, workflow_id)
     VALUES (?, ?, 'running', ?, ?)`,
    [runId, startedAt, triggerMode, workflowId],
    (err) => err ? reject(err) : resolve()
  );
});
await new Promise((resolve) => db.close(() => resolve()));

// Pass the trigger's input through unchanged so Read Export File still runs once.
const items = $input.all();
const passthrough = items.length > 0 ? items : [{ json: {} }];
return passthrough.map(item => ({
  json: { ...item.json, _run_id: runId, _started_at: startedAt, _trigger_mode: triggerMode }
}));

// Shape Rows: single source of truth for the column mapping. Consumes items
// from Compute Divergence and produces a normalized shape that Upsert Daily,
// Upsert Trades, and Build Summary can all consume without re-extracting.
const items = $input.all();
const out = [];

for (const item of items) {
  const d = item.json;

  const daily_row = {
    city:              d.city,
    market_date:       d.date,
    station:           d.station ?? null,
    wu_temp:           d.wu_temp ?? null,
    om_temp:           d.om_temp ?? null,
    iem_temp:          d.iem_temp ?? null,
    om_divergence:     d.om_divergence ?? null,
    iem_divergence:    d.iem_divergence ?? null,
    om_iem_divergence: d.om_iem_divergence ?? null,
    bracket_unit:      d.bracket_unit ?? null,
    n_trades:          d.n_trades ?? null,
    om_n_flipped:      d.om_n_flipped ?? null,
    iem_n_flipped:     d.iem_n_flipped ?? null,
    has_om:            d.has_om ? 1 : 0,
    has_iem:           d.has_iem ? 1 : 0,
    has_wu:            d.has_wu ? 1 : 0,
  };

  const trade_rows = (d.trade_details || []).map(t => ({
    trade_id:       String(t.trade_id),
    city:           d.city,
    market_date:    d.date,
    bracket_label:  t.bracket_label ?? null,
    side:           t.side ?? null,
    entry_price:    t.entry_price ?? null,
    pnl:            t.pnl ?? null,
    model_prob:     t.model_prob ?? null,
    market_prob:    t.market_prob ?? null,
    wu_temp:        d.wu_temp ?? null,
    om_temp:        d.om_temp ?? null,
    iem_temp:       d.iem_temp ?? null,
    om_divergence:  d.om_divergence ?? null,
    iem_divergence: d.iem_divergence ?? null,
    wu_hit:     t.wu_hit     == null ? null : (t.wu_hit     ? 1 : 0),
    om_hit:     t.om_hit     == null ? null : (t.om_hit     ? 1 : 0),
    iem_hit:    t.iem_hit    == null ? null : (t.iem_hit    ? 1 : 0),
    om_flipped: t.om_flipped == null ? null : (t.om_flipped ? 1 : 0),
    iem_flipped:t.iem_flipped== null ? null : (t.iem_flipped? 1 : 0),
  }));

  out.push({
    json: {
      daily_row,
      trade_rows,
      // Keep the raw fields available too — Build Summary uses them directly.
      city: d.city,
      date: d.date,
      n_trades: d.n_trades,
      om_iem_divergence: d.om_iem_divergence,
      trade_details: d.trade_details,
    }
  });
}

return out;

// Upsert Daily: UPSERT one row per (city, market_date) into divergences_daily.
// Replaces the old Build Daily CSV + Save Daily CSV pair.
const sqlite3 = require('sqlite3');
const items = $input.all();
const runId = $('Start Run').first().json._run_id;
const nowIso = new Date().toISOString();

const db = new sqlite3.Database('/data/wethr/wethr_audit.db');
const runSql = (sql, params=[]) => new Promise((resolve, reject) => {
  db.run(sql, params, function(err) { err ? reject(err) : resolve(this); });
});

const SQL = `
INSERT INTO divergences_daily
  (city, market_date, station, wu_temp, om_temp, iem_temp,
   om_divergence, iem_divergence, om_iem_divergence,
   bracket_unit, n_trades, om_n_flipped, iem_n_flipped,
   has_om, has_iem, has_wu,
   first_seen_run_id, first_seen_at, last_seen_run_id, last_seen_at)
VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
ON CONFLICT(city, market_date) DO UPDATE SET
  station           = excluded.station,
  wu_temp           = excluded.wu_temp,
  om_temp           = excluded.om_temp,
  iem_temp          = excluded.iem_temp,
  om_divergence     = excluded.om_divergence,
  iem_divergence    = excluded.iem_divergence,
  om_iem_divergence = excluded.om_iem_divergence,
  bracket_unit      = excluded.bracket_unit,
  n_trades          = excluded.n_trades,
  om_n_flipped      = excluded.om_n_flipped,
  iem_n_flipped     = excluded.iem_n_flipped,
  has_om            = excluded.has_om,
  has_iem           = excluded.has_iem,
  has_wu            = excluded.has_wu,
  last_seen_run_id  = excluded.last_seen_run_id,
  last_seen_at      = excluded.last_seen_at
`;

let upserted = 0;
try {
  await runSql('BEGIN');
  for (const item of items) {
    const r = item.json.daily_row;
    if (!r) continue;
    await runSql(SQL, [
      r.city, r.market_date, r.station, r.wu_temp, r.om_temp, r.iem_temp,
      r.om_divergence, r.iem_divergence, r.om_iem_divergence,
      r.bracket_unit, r.n_trades, r.om_n_flipped, r.iem_n_flipped,
      r.has_om, r.has_iem, r.has_wu,
      runId, nowIso, runId, nowIso
    ]);
    upserted++;
  }
  await runSql('COMMIT');
} catch (e) {
  await runSql('ROLLBACK').catch(() => {});
  await new Promise(r => db.close(() => r()));
  throw e;
}
await new Promise(r => db.close(() => r()));

return [{ json: { table: 'divergences_daily', upserted, run_id: runId } }];

// Upsert Trades: UPSERT one row per trade_id into divergences_trades.
// Replaces the old Build Trade CSV + Save Trade CSV pair.
const sqlite3 = require('sqlite3');
const items = $input.all();
const runId = $('Start Run').first().json._run_id;
const nowIso = new Date().toISOString();

const db = new sqlite3.Database('/data/wethr/wethr_audit.db');
const runSql = (sql, params=[]) => new Promise((resolve, reject) => {
  db.run(sql, params, function(err) { err ? reject(err) : resolve(this); });
});

const SQL = `
INSERT INTO divergences_trades
  (trade_id, city, market_date, bracket_label, side,
   entry_price, pnl, model_prob, market_prob,
   wu_temp, om_temp, iem_temp, om_divergence, iem_divergence,
   wu_hit, om_hit, iem_hit, om_flipped, iem_flipped,
   first_seen_run_id, first_seen_at, last_seen_run_id, last_seen_at)
VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
ON CONFLICT(trade_id) DO UPDATE SET
  city            = excluded.city,
  market_date     = excluded.market_date,
  bracket_label   = excluded.bracket_label,
  side            = excluded.side,
  entry_price     = excluded.entry_price,
  pnl             = excluded.pnl,
  model_prob      = excluded.model_prob,
  market_prob     = excluded.market_prob,
  wu_temp         = excluded.wu_temp,
  om_temp         = excluded.om_temp,
  iem_temp        = excluded.iem_temp,
  om_divergence   = excluded.om_divergence,
  iem_divergence  = excluded.iem_divergence,
  wu_hit          = excluded.wu_hit,
  om_hit          = excluded.om_hit,
  iem_hit         = excluded.iem_hit,
  om_flipped      = excluded.om_flipped,
  iem_flipped     = excluded.iem_flipped,
  last_seen_run_id = excluded.last_seen_run_id,
  last_seen_at     = excluded.last_seen_at
`;

let upserted = 0;
try {
  await runSql('BEGIN');
  for (const item of items) {
    const rows = item.json.trade_rows || [];
    for (const r of rows) {
      await runSql(SQL, [
        r.trade_id, r.city, r.market_date, r.bracket_label, r.side,
        r.entry_price, r.pnl, r.model_prob, r.market_prob,
        r.wu_temp, r.om_temp, r.iem_temp, r.om_divergence, r.iem_divergence,
        r.wu_hit, r.om_hit, r.iem_hit, r.om_flipped, r.iem_flipped,
        runId, nowIso, runId, nowIso
      ]);
      upserted++;
    }
  }
  await runSql('COMMIT');
} catch (e) {
  await runSql('ROLLBACK').catch(() => {});
  await new Promise(r => db.close(() => r()));
  throw e;
}
await new Promise(r => db.close(() => r()));

return [{ json: { table: 'divergences_trades', upserted, run_id: runId } }];

// Finish Run: update audit_runs with completion status and upsert counts.
// Runs once after the three downstream branches (Upsert Daily, Upsert Trades,
// Send Telegram Summary) have all completed via the Finalize Merge node.
const sqlite3 = require('sqlite3');
const runId = $('Start Run').first().json._run_id;
const finishedAt = new Date().toISOString();

// Pull counts from the two upsert nodes (they each emit {upserted, ...}).
const daily  = $('Upsert Daily').all();
const trades = $('Upsert Trades').all();
const dailyCount = daily.reduce((s, i) => s + (i.json.upserted || 0), 0);
const tradeCount = trades.reduce((s, i) => s + (i.json.upserted || 0), 0);

// Count how many trades were fed into the audit (before divergence compute).
let nTradesInput = 0;
try {
  const settled = $('Read Settled Trades').all();
  for (const it of settled) {
    const ts = it.json && it.json.trades;
    if (Array.isArray(ts)) nTradesInput += ts.length;
  }
} catch (e) { /* best-effort */ }

const db = new sqlite3.Database('/data/wethr/wethr_audit.db');
await new Promise((resolve, reject) => {
  db.run(
    `UPDATE audit_runs
        SET finished_at = ?,
            status = 'completed',
            daily_rows_upserted = ?,
            trade_rows_upserted = ?,
            n_trades_input = ?
      WHERE run_id = ?`,
    [finishedAt, dailyCount, tradeCount, nTradesInput, runId],
    (err) => err ? reject(err) : resolve()
  );
});
await new Promise(r => db.close(() => r()));

return [{
  json: {
    run_id: runId,
    status: 'completed',
    finished_at: finishedAt,
    daily_rows_upserted: dailyCount,
    trade_rows_upserted: tradeCount,
    n_trades_input: nTradesInput,
  }
}];

// Finish Run (No Trades): the 'no settled trades today' path still needs to
// close out the audit_runs row cleanly so we don't leave it stuck on 'running'.
const sqlite3 = require('sqlite3');
const runId = $('Start Run').first().json._run_id;
const finishedAt = new Date().toISOString();

const db = new sqlite3.Database('/data/wethr/wethr_audit.db');
await new Promise((resolve, reject) => {
  db.run(
    `UPDATE audit_runs
        SET finished_at = ?,
            status = 'completed',
            n_trades_input = 0,
            notes = 'no settled trades in input'
      WHERE run_id = ?`,
    [finishedAt, runId],
    (err) => err ? reject(err) : resolve()
  );
});
await new Promise(r => db.close(() => r()));

return [{ json: { run_id: runId, status: 'completed', notes: 'no trades' } }];
